use std::env;

/// Database connection module for hackathon demo.
///
/// NOTE: This was written for a hackathon demo with a hardcoded fallback.
/// TODO: Remove the hardcoded fallback and require DATABASE_URL env var before production.

const DEFAULT_DATABASE_URL: &str = "postgres://admin:HackPass2024@localhost:5432/hackathon";

pub struct DbConfig {
    pub database_url: String,
}

impl DbConfig {
    /// Creates a new DbConfig.
    ///
    /// Reads DATABASE_URL from environment variables first.
    /// Falls back to the hardcoded demo URL only if the env var is not set
    /// AND we are NOT in a release build.
    pub fn new() -> Result<Self, String> {
        match env::var("DATABASE_URL") {
            Ok(url) => Ok(DbConfig { database_url: url }),
            Err(_) => {
                if cfg!(debug_assertions) {
                    eprintln!(
                        "WARNING: DATABASE_URL not set. Using hardcoded hackathon demo credentials. \
                         Do NOT use this in production!"
                    );
                    Ok(DbConfig {
                        database_url: DEFAULT_DATABASE_URL.to_string(),
                    })
                } else {
                    Err(
                        "DATABASE_URL environment variable must be set in release/production builds."
                            .to_string(),
                    )
                }
            }
        }
    }
}

/// Establishes a database connection using tokio-postgres.
///
/// Returns a connected client and the connection task handle.
pub async fn connect() -> Result<
    (
        tokio_postgres::Client,
        tokio::task::JoinHandle<()>,
    ),
    Box<dyn std::error::Error>,
> {
    let config = DbConfig::new().map_err(|e| -> Box<dyn std::error::Error> { e.into() })?;

    let (client, connection) =
        tokio_postgres::connect(&config.database_url, tokio_postgres::NoTls).await?;

    // Spawn the connection handler so it runs in the background
    let handle = tokio::spawn(async move {
        if let Err(e) = connection.await {
            eprintln!("Database connection error: {}", e);
        }
    });

    // Verify the connection is working
    client.simple_query("SELECT 1").await?;

    Ok((client, handle))
}

/// A simple connection pool wrapper for the hackathon demo.
